{"Configuration":"/** @param {Context} context */
const SetValue = async (context) => {
    // Define a mapping of fields to their corresponding display values
    const items = [
        { field: context?.Form?.Page4?.Circuits?.Value, label: "Circuits" },
        { field: context?.Form?.Page4?.SubpanelMainPanel?.Value, label: "Electrical Panel" },
        { field: context?.Form?.Page4?.SingleHeadDuctlessMiniSplits?.Value, label: "Single-Head Ductless Mini Split" },
        { field: context?.Form?.Page4?.MultiHeadDuctlessMinisplits?.Value, label: "Multi-Head Ductless Mini Split" },
        { field: context?.Form?.Page4?.WaterHeater?.Value, label: "Water Heater" },
        { field: context?.Form?.Page4?.CentralHeatPump?.Value, label: "Central Heat Pump" },
        { field: context?.Form?.Page4?.SmartThermostat?.Value, label: "Smart Thermostat" },
        { field: context?.Form?.Page4?.AtticInsulation?.Value, label: "Attic Insulation" },
        { field: context?.Form?.Page4?.CookingStovetopCookware?.Value, label: "Cooking Stovetop Cookware" },
        { field: context?.Form?.Page4?.ClothesDryer?.Value, label: "Clothes Dryer" },
        { field: context?.Form?.Page4?.MinorHomeRepair?.Value, label: "Minor Home Repair" },
        { field: context?.Form?.Page4?.WholeHomeBatteryCheckbox?.Value, label: "Whole Home Battery" }
    ];

    // Filter only items that have a truthy value
    const selectedItems = items
        .filter(item => !!item.field) // Keep only those that are true
        .map(item => item.label); // Extract labels

    // Return the joined string, or an empty string if nothing is selected
    return selectedItems.length > 0 ? selectedItems.join(", ") : "";
};
