{"Configuration":"/** @param {Context} context */
const SetValue = async (context) => {
    const maromaStatus = context?.Form?.Page4?.MAROMAReviewStatus?.Value || "";
    const contractorStatus = context?.Form?.Page4?.ContractorSubmissionStatus?.Value || "";

    // Canceled - highest priority (either status)
    if (contractorStatus == "Canceled") {
        return "Canceled";
    }

    // MAROMA status takes precedence
    if (maromaStatus == "Enrollment Approved") {
        return "Enrollment Approved";
    }
    if (maromaStatus == "Corrections Required") {
        return "Corrections Required";
    }
    if (contractorStatus == "Draft Pending") {
        return "Draft"
    }


    if (contractorStatus == "Ready for Review" && maromaStatus == "Pending Review") {
        return "Pending Review";
    }

    // Review checklist validation (only if MAROMA hasn't set a status)
    const reviewChecklist = context?.Form?.Page4?.EnrollmentReviewChecklist?.Value || "";
    if (reviewChecklist !== "") {
        if (reviewChecklist.includes("Calculator") && reviewChecklist.includes("Documentation")) {
            return "Pending Review";
        } else if (reviewChecklist.includes("Calculator")) {
            return "Pending Documentation Review";
        } else if (reviewChecklist.includes("Documentation")) {
            return "Pending Calculator Review";
        }
    }

    // Contractor submitted but no MAROMA review yet
    if (contractorStatus == "Ready for Review") {
        return "Pending Review";
    }

    // Default
    return "Draft";
}","ClearValueOnTrue":false,"ClearValueOnFalse":false,"Fields":[{"ModelKey":"Form.Page4.EnrollmentReviewChecklist","FieldName":"EnrollmentReviewChecklist","IsSystemModelKey":false},{"ModelKey":"Form.Page4.MAROMAReviewStatus","FieldName":"MAROMAReviewStatus","IsSystemModelKey":false},{"ModelKey":"Form.Page4.ContractorSubmissionStatus","FieldName":"ContractorSubmissionStatus","IsSystemModelKey":false}]}

