    const furnace2 = !!context?.Form?.HVACPage?.CentralFurnaceEligibility2?.Value;
    const airConditioner1 = !!context?.Form?.HVACPage?.AirConditionerEligibility1?.Value;
    const airConditioner2 = !!context?.Form?.HVACPage?.AirConditionerEligibility2?.Value;

    // Detached furnace eligibility
    const wallFurnace = !!context?.Form?.ProjectResultsPage?.WallFurnaceEligibility?.Value;
    const floorFurnace = !!context?.Form?.ProjectResultsPage?.FloorFurnaceEligibility?.Value;

    // Water heater eligibility
    const waterHeater1 = !!context?.Form?.WaterHeaterPage?.WaterHeaterEligibility1?.Value;
    const waterHeater2 = !!context?.Form?.WaterHeaterPage?.WaterHeaterEligibility2?.Value;

    // Extract central HVAC qty string
    const centralHVACqty = context?.Form?.HVACPage?.HowmanyCentralHVACsystemareinthehome?.Value || "0";

    // Minisplit eligibility
    const miniSplit1 = !!context?.Form?.HVACPage?.MinisplitEligibility1?.Value;

    // Check water heater eligibility
    const allWaterHeatersEligible =
        waterHeater1 === true && (!waterHeater2 || waterHeater2 === true);

    // Check heating equipment eligibility
    const isHeatingEquipmentEligible =
        (centralHVACqty === "2" && furnace1 === true && furnace2 === true) ||
        furnace1 === true ||
        wallFurnace === true ||
        floorFurnace === true;

    // Check cooling eligibility
    const isCoolingEligible =
        (airConditioner2 === true && airConditioner1 === true) ||
        airConditioner1 === true ||
        miniSplit1 === true;

    // Final eligibility check
    const isEligible = isHeatingEquipmentEligible && allWaterHeatersEligible;

    // Return override status or calculated eligibility
    if (eligibilityOverride) {
        return "Project is Eligible for Approval Phase";
    }

